// Process YoY Data  (REPLACE with this version that outputs a YoY table pack)

const currentData = $('Excel: Get Current Period').first().json;
const previousData = $('Excel: Get Previous Period').first().json;

function safeNum(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function pct(a, b) {
  if (!b) return null;
  return (a / b) * 100;
}

function fmtInt(x) {
  return Math.round(x).toLocaleString();
}
function fmtMoney0(x) {
  return `£${Math.round(x).toLocaleString()}`;
}
function fmtMoney2(x) {
  return `£${Number(x).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}
function fmtPct2(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "";
  return `${Number(x).toFixed(2)}%`;
}
function fmtVar1(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "";
  const v = Number(x);
  return `${v >= 0 ? "+" : ""}${v.toFixed(1)}%`;
}

function calc(d) {
  const clicks = safeNum(d.clicks);
  const sales = safeNum(d.sales);
  const orderValue = safeNum(d.orderValue);
  const aov = sales ? (orderValue / sales) : 0;

  const pubCommission = safeNum(d.publisherCommission);
  const tdCommission = safeNum(d.tdCommission);
  const totalCommission = pubCommission + tdCommission;

  // If your sheet has cost or spend, map it here; otherwise keep 0
  const cost = safeNum(d.cost ?? d.spend ?? d.mediaCost ?? 0);

  const convRate = clicks ? pct(sales, clicks) : 0;                // %
  const cpa = sales ? (totalCommission / sales) : 0;               // £ per sale (commission CPA)
  const roi = totalCommission ? (orderValue / totalCommission) : 0; // ratio

  return {
    clicks, sales, convRate, orderValue, aov,
    pubCommission, totalCommission,
    cpa, roi
  };
}

const cur = calc(currentData);
const prev = calc(previousData);

function diff(a, b) { return a - b; }
function varPct(a, b) { return b ? ((a - b) / b * 100) : null; }

const rows = [
  {
    Row: "Recent",
    Clicks: fmtInt(cur.clicks),
    Sales: fmtInt(cur.sales),
    "Conv Rate": fmtPct2(cur.convRate),
    "Order value": fmtMoney0(cur.orderValue),
    "AOV": fmtMoney2(cur.aov),
    "Publ Commission": fmtMoney0(cur.pubCommission),
    "Total Commission": fmtMoney0(cur.totalCommission),
    "CPA": fmtMoney2(cur.cpa),
    "ROI": cur.roi ? cur.roi.toFixed(2) : ""
  },
  {
    Row: "Previous",
    Clicks: fmtInt(prev.clicks),
    Sales: fmtInt(prev.sales),
    "Conv Rate": fmtPct2(prev.convRate),
    "Order value": fmtMoney0(prev.orderValue),
    "AOV": fmtMoney2(prev.aov),
    "Publ Commission": fmtMoney0(prev.pubCommission),
    "Total Commission": fmtMoney0(prev.totalCommission),
    "CPA": fmtMoney2(prev.cpa),
    "ROI": prev.roi ? prev.roi.toFixed(2) : ""
  },
  {
    Row: "Difference",
    Clicks: (diff(cur.clicks, prev.clicks) >= 0 ? "+" : "") + fmtInt(diff(cur.clicks, prev.clicks)),
    Sales: (diff(cur.sales, prev.sales) >= 0 ? "+" : "") + fmtInt(diff(cur.sales, prev.sales)),
    "Conv Rate": fmtPct2(diff(cur.convRate, prev.convRate)),
    "Order value": (diff(cur.orderValue, prev.orderValue) >= 0 ? "+" : "") + fmtMoney0(diff(cur.orderValue, prev.orderValue)).replace("£", "£"),
    "AOV": fmtMoney2(diff(cur.aov, prev.aov)),
    "Publ Commission": (diff(cur.pubCommission, prev.pubCommission) >= 0 ? "+" : "") + fmtMoney0(diff(cur.pubCommission, prev.pubCommission)).replace("£", "£"),
    "Total Commission": (diff(cur.totalCommission, prev.totalCommission) >= 0 ? "+" : "") + fmtMoney0(diff(cur.totalCommission, prev.totalCommission)).replace("£", "£"),
    "CPA": fmtMoney2(diff(cur.cpa, prev.cpa)),
    "ROI": diff(cur.roi, prev.roi).toFixed(2)
  },
  {
    Row: "% Variance",
    Clicks: fmtVar1(varPct(cur.clicks, prev.clicks)),
    Sales: fmtVar1(varPct(cur.sales, prev.sales)),
    "Conv Rate": fmtVar1(varPct(cur.convRate, prev.convRate)),
    "Order value": fmtVar1(varPct(cur.orderValue, prev.orderValue)),
    "AOV": fmtVar1(varPct(cur.aov, prev.aov)),
    "Publ Commission": fmtVar1(varPct(cur.pubCommission, prev.pubCommission)),
    "Total Commission": fmtVar1(varPct(cur.totalCommission, prev.totalCommission)),
    "CPA": fmtVar1(varPct(cur.cpa, prev.cpa)),
    "ROI": fmtVar1(varPct(cur.roi, prev.roi))
  }
];

const dataForAI = `Program YoY Summary Table (Recent vs Previous)\n${JSON.stringify(rows, null, 2)}`;

return [{
  json: {
    dataForAI,
    programYoYTable: rows
  }
}];

// Process Publisher QBR Pack - YoY Comparison Between Two Excel Sheets
// UPDATED: Now filters tiny-base publishers to prevent misleading growth percentages

function safeNum(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function fmtMoney0(x) {
  return `£${Math.round(x).toLocaleString()}`;
}

function fmtInt(x) {
  return Math.round(x).toLocaleString();
}

function fmtYoY(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "N/A";
  const v = Number(x);
  if (!Number.isFinite(v)) return "N/A";
  return `${v >= 0 ? "+" : ""}${v.toFixed(1)}%`;
}

// ═══════════════════════════════════════════════════════════
// CONFIGURATION
// ═══════════════════════════════════════════════════════════
const MINIMUM_PREVIOUS_OV = 2000; // £2k threshold
// ═══════════════════════════════════════════════════════════
// STEP 1: Get Current Period Data
// ═══════════════════════════════════════════════════════════
const currentRows = $('Excel: Get Publisher Rows1').all().map(i => i.json);

// ═══════════════════════════════════════════════════════════
// STEP 2: Get Previous Period Data
// ═══════════════════════════════════════════════════════════
const previousRows = $('Excel: Get Publisher Rows 2025').all().map(i => i.json);

// ═══════════════════════════════════════════════════════════
// STEP 3: Create Lookup Map for Previous Period
// ═══════════════════════════════════════════════════════════
const previousMap = new Map();
for (const row of previousRows) {
  const pubName = row.sourceName ?? "Unknown";
  previousMap.set(pubName, {
    prevOV: safeNum(row.orderValue),
    prevSales: safeNum(row.sales),
    prevClicks: safeNum(row.clicks),
    prevPubCommission: safeNum(row.publisherCommission)
  });
}

// ═══════════════════════════════════════════════════════════
// STEP 4: Calculate YoY for Each Publisher
// ═══════════════════════════════════════════════════════════
const rows = currentRows.map(d => {
  const publisher = d.sourceName ?? "Unknown";
  const currentOV = safeNum(d.orderValue);
  const currentSales = safeNum(d.sales);
  const currentClicks = safeNum(d.clicks);
  const currentPubComm = safeNum(d.publisherCommission);

  // Get previous period data (or default to 0)
  const prev = previousMap.get(publisher) || { 
    prevOV: 0, 
    prevSales: 0, 
    prevClicks: 0,
    prevPubCommission: 0
  };

  // Calculate ABSOLUTE YoY changes (£ difference)
  const ovYoYAbsolute = currentOV - prev.prevOV;
  const salesYoYAbsolute = currentSales - prev.prevSales;
  const clicksYoYAbsolute = currentClicks - prev.prevClicks;

  // Calculate PERCENTAGE YoY changes
  const ovYoYPercent = prev.prevOV > 0 
    ? ((currentOV - prev.prevOV) / prev.prevOV * 100) 
    : null;

  const salesYoYPercent = prev.prevSales > 0
    ? ((currentSales - prev.prevSales) / prev.prevSales * 100)
    : null;

  // Calculate CPA
  const cpa = currentSales > 0 ? (currentPubComm / currentSales) : 0;

  // Classify growth category
  let growthCategory = "Established";
  if (prev.prevOV < MINIMUM_PREVIOUS_OV && prev.prevOV > 0) {
    growthCategory = "New/Emerging";
  } else if (prev.prevOV === 0) {
    growthCategory = "Brand New";
  } else if (ovYoYPercent > 500) {
    growthCategory = "Explosive Growth";
  } else if (ovYoYPercent > 100) {
    growthCategory = "High Growth";
  } else if (ovYoYPercent > 25) {
    growthCategory = "Growing";
  } else if (ovYoYPercent < -25) {
    growthCategory = "Declining";
  }

  return {
    publisher,
    // Current period data
    ov: currentOV,
    sales: currentSales,
    clicks: currentClicks,
    pubCommission: currentPubComm,
    cpa,
    // YoY changes
    ovYoYAbsolute,
    ovYoYPercent,
    salesYoYAbsolute,
    salesYoYPercent,
    clicksYoYAbsolute,
    // Previous period baseline
    prevOV: prev.prevOV,
    // Classification
    growthCategory
  };
});

// ═══════════════════════════════════════════════════════════
// STEP 5: Separate Established vs New/Emerging Publishers
// ═══════════════════════════════════════════════════════════

// Established publishers (previous OV >= £10k OR decliners)
const establishedRows = rows.filter(r => {
  return r.prevOV >= MINIMUM_PREVIOUS_OV || r.ovYoYAbsolute < 0;
});

// New/Emerging publishers (previous OV < £10k AND positive growth)
const newEmergingRows = rows.filter(r => {
  return r.prevOV < MINIMUM_PREVIOUS_OV && r.prevOV > 0 && r.ovYoYAbsolute > 0;
});

// Brand new publishers (no previous data)
const brandNewRows = rows.filter(r => r.prevOV === 0);

// ═══════════════════════════════════════════════════════════
// STEP 6: Generate Top 10 Tables (Using Established Publishers)
// ═══════════════════════════════════════════════════════════

// 1. TOP 10 YoY OV INCREASE (by absolute £ change - ESTABLISHED ONLY)
const top10Increase = establishedRows
  .filter(r => r.ovYoYAbsolute > 0)
  .sort((a, b) => b.ovYoYAbsolute - a.ovYoYAbsolute)
  .slice(0, 10)
  .map(r => ({
    Publisher: r.publisher,
    "Current OV": fmtMoney0(r.ov),
    "Previous OV": fmtMoney0(r.prevOV),
    "YoY Change £": fmtMoney0(r.ovYoYAbsolute),
    "YoY %": fmtYoY(r.ovYoYPercent),
    "Sales": fmtInt(r.sales)
  }));

// 2. TOP 10 YoY OV DECREASE (by absolute £ change)
const top10Decrease = establishedRows
  .filter(r => r.ovYoYAbsolute < 0)
  .sort((a, b) => a.ovYoYAbsolute - b.ovYoYAbsolute)
  .slice(0, 10)
  .map(r => ({
    Publisher: r.publisher,
    "Current OV": fmtMoney0(r.ov),
    "Previous OV": fmtMoney0(r.prevOV),
    "YoY Change £": fmtMoney0(r.ovYoYAbsolute),
    "YoY %": fmtYoY(r.ovYoYPercent),
    "Sales": fmtInt(r.sales)
  }));

// 3. TOP 10 PUBLISHERS BY CURRENT OV (ALL publishers)
const top10ByOV = rows
  .sort((a, b) => b.ov - a.ov)
  .slice(0, 10)
  .map(r => ({
    Publisher: r.publisher,
    "Order Value": fmtMoney0(r.ov),
    "Sales": fmtInt(r.sales),
    "Pub Commission": fmtMoney0(r.pubCommission),
    "CPA": r.cpa > 0 ? fmtMoney0(r.cpa) : "N/A",
    "YoY %": fmtYoY(r.ovYoYPercent),
    "Category": r.growthCategory
  }));

// 4. TOP 10 NEW/EMERGING PUBLISHERS (separate table)
const top10NewEmerging = newEmergingRows
  .sort((a, b) => b.ov - a.ov) // Sort by current OV
  .slice(0, 10)
  .map(r => ({
    Publisher: r.publisher,
    "Current OV": fmtMoney0(r.ov),
    "Previous OV": fmtMoney0(r.prevOV),
    "Absolute Growth": fmtMoney0(r.ovYoYAbsolute),
    "Sales": fmtInt(r.sales),
    "Status": r.prevOV < 5000 ? "Brand New Activation" : "Rapid Scale-Up"
  }));

// 5. BRAND NEW PUBLISHERS (no previous data)
const top10BrandNew = brandNewRows
  .sort((a, b) => b.ov - a.ov)
  .slice(0, 10)
  .map(r => ({
    Publisher: r.publisher,
    "Current OV": fmtMoney0(r.ov),
    "Sales": fmtInt(r.sales),
    "CPA": r.cpa > 0 ? fmtMoney0(r.cpa) : "N/A"
  }));

// ═══════════════════════════════════════════════════════════
// STEP 7: Segment Analysis
// ═══════════════════════════════════════════════════════════
function inferSegment(nameRaw) {
  const name = String(nameRaw || "").toLowerCase();
  if (/(css|google shopping|comparison|compare|idealo|shoparize|genie shopping)/.test(name)) 
    return "CSS";
  if (/(which|techradar|trustedreviews|guardian|telegraph|independent|media|content)/.test(name)) 
    return "Content";
  if (/(voucher|coupon|deal|discount|hotukdeals|vouchercodes)/.test(name)) 
    return "Voucher";
  if (/(cashback|quidco|topcashback)/.test(name)) 
    return "Cashback";
  return "Other";
}

const segmentPerformance = {};
for (const r of establishedRows) { // Use established only for segment analysis
  const seg = inferSegment(r.publisher);
  if (!segmentPerformance[seg]) {
    segmentPerformance[seg] = { ov: 0, ovYoYChange: 0, sales: 0, count: 0 };
  }
  segmentPerformance[seg].ov += r.ov;
  segmentPerformance[seg].ovYoYChange += r.ovYoYAbsolute;
  segmentPerformance[seg].sales += r.sales;
  segmentPerformance[seg].count += 1;
}

const segmentSummary = Object.entries(segmentPerformance)
  .map(([seg, data]) => ({
    Segment: seg,
    "Total OV": fmtMoney0(data.ov),
    "YoY Change £": fmtMoney0(data.ovYoYChange),
    "YoY %": fmtYoY(data.ov > 0 && data.ovYoYChange !== 0 
      ? (data.ovYoYChange / (data.ov - data.ovYoYChange) * 100) 
      : null),
    "Publishers": data.count
  }))
  .sort((a, b) => segmentPerformance[b.Segment].ov - segmentPerformance[a.Segment].ov);

// ═══════════════════════════════════════════════════════════
// STEP 8: Prepare Output for AI
// ═══════════════════════════════════════════════════════════
const dataForAI = {
  // Established publisher insights
  top10Increase,
  top10Decrease,
  top10ByOV,
  segmentSummary,

  // New/Emerging publisher insights
  top10NewEmerging,
  top10BrandNew,

  // Summary statistics
  totalPublishers: rows.length,
  establishedPublishers: establishedRows.length,
  newEmergingPublishers: newEmergingRows.length,
  brandNewPublishers: brandNewRows.length,
  publishersWithGrowth: establishedRows.filter(r => r.ovYoYAbsolute > 0).length,
  publishersWithDecline: establishedRows.filter(r => r.ovYoYAbsolute < 0).length,

  // Context notes
  dataQualityNote: `Analysis separates ${establishedRows.length} established publishers (£10k+ previous OV) from ${newEmergingRows.length} new/emerging partners (small base) and ${brandNewRows.length} brand new activations to prevent misleading growth percentages.`,

  topGrowthSegment: segmentSummary[0]?.Segment || "N/A"
};

return [{
  json: {
    publisherPerformanceTables: {
      // Main tables (established publishers)
      top10Increase,
      top10Decrease,
      top10ByOV,
      segmentSummary,

      // Separate tables for new publishers
      top10NewEmerging,
      top10BrandNew
    },
    dataForAI: JSON.stringify(dataForAI, null, 2),

    // Metadata for debugging
    metadata: {
      minimumPreviousOVThreshold: MINIMUM_PREVIOUS_OV,
      totalPublishers: rows.length,
      establishedPublishers: establishedRows.length,
      newEmergingPublishers: newEmergingRows.length,
      brandNewPublishers: brandNewRows.length
    }
  }
}];

// Build Final Response - COMPLETE v2.0
// Handles Program YoY, Publisher Performance, and Visibility Analysis

// Get all items from the merge (3 branches)
const allItems = $input.all().map(item => item.json);

// Extract data from each branch
const programData = allItems.find(item => item.programOutput) || {};
const publisherData = allItems.find(item => item.publisherAnalysis) || {};
const visibilityData = allItems.find(item => item.visibilityAnalysis) || {};

// === PROGRAM YOY DATA ===
const program = programData.programOutput || "(No program analysis returned)";
const programYoYTable = programData.programYoYTable || [];

// === PUBLISHER DATA ===
const publisherAnalysis = publisherData.publisherAnalysis || "(No publisher analysis returned)";
const publisherTables = publisherData.publisherTables || {};

// === VISIBILITY DATA ===
