  // Publisher type classification
  if (/(voucher|coupon|discount|code|deal|promo|vouchercodes|vouchercloud|savoo|myvouchercodes)/.test(d)) {
    return "voucher_discount";
  }
  if (/(hotukdeals|hukd|slickdeals)/.test(d)) {
    return "deal_community";
  }
  if (/(quidco|topcashback|cashback|easyfundraising)/.test(d)) {
    return "cashback";
  }
  if (/(bluelight|totum|studentbeans|unidays)/.test(d)) {
    return "closed_user_group";
  }
  if (/(idealo|compare|pricerunner|google\..*\/shopping)/.test(d)) {
    return "css";
  }
  if (/(which\.co\.uk|techradar|trustedreviews|t3\.com|expertreviews|housebeautiful|stuff\.tv|pocket-lint)/.test(d)) {
    return "editorial";
  }
  if (/(trustpilot|reviews\.co\.uk|feefo|reevoo)/.test(d)) {
    return "review_ugc";
  }
  if (/(reddit|mumsnet|moneysavingexpert|forums?|pistonheads)/.test(d)) {
    return "forum_community";
  }
  if (d.includes(brand)) {
    return "brand_owned";
  }
  if (/(amazon|argos|currys|johnlewis|very|ebay|asos|ao\.com|appliancesdirect)/.test(d)) {
    return "retailer";
  }
  return "other";
}

function extractPageAngle(title) {
  const t = title.toLowerCase();

  // Extract key content angle
  if (/best.*202[56]/.test(t)) {
    const match = t.match(/best\s+([a-z\s]+)\s+202[56]/);
    return match ? `best ${match[1].trim()} guide` : "best guide 2025/2026";
  }
  if (/discount|code|voucher|promo/.test(t)) return "discount codes";
  if (/review/.test(t)) return "reviews";
  if (/vs|versus|compared/.test(t)) return "comparison";
  if (/is\s+\w+\s+(good|legit|worth|reliable)/.test(t)) return "legitimacy check";
  if (/deals|offers/.test(t)) return "deals";
  if (/what\s+\w+\s+to\s+(avoid|trust|buy)/.test(t)) return "buyer advice";
  if (/trend|shaping|expert/.test(t)) return "trends & insights";

  // Default: take first 3-5 words
  const words = t.split(' ').filter(w => w.length > 2).slice(0, 4);
  return words.join(' ') || "general content";
}

