function checkFreshness(title, snippet, publishDate) {
  const text = (title + " " + snippet).toLowerCase();
  const currentYear = new Date().getFullYear();
  const currentMonth = new Date().toLocaleString('en', { month: 'short' });

  // Check publish date if available
  if (publishDate) {
    const pd = publishDate.toLowerCase();

    // Very fresh - current month/year
    if (pd.includes(String(currentYear)) && pd.includes(currentMonth)) {
      return "very_fresh";
    }
    // Fresh - within last 3 months
    if (pd.includes(String(currentYear))) {
      return "fresh";
    }
    // Evergreen - old date
    if (pd.includes(String(currentYear - 1)) || pd.includes(String(currentYear - 2))) {
      return "evergreen";
    }
  }

  // Check content for freshness signals
  if (text.includes(String(currentYear))) return "fresh";
  if (text.includes(String(currentYear - 1))) return "fresh";

  return "evergreen";
}

function calculateOpportunityScore(result) {
  let score = 0;

  // Query type value
  if (result.queryType === "commercial") score += 30;
  else if (result.queryType === "comparison") score += 25;
  else if (result.queryType === "informational") score += 20;

  // Position
  if (result.position <= 3) score += 25;
  else if (result.position <= 5) score += 15;
  else if (result.position <= 10) score += 10;

  // Publisher type (updated with deal_community)
  const highValue = ["voucher_discount", "deal_community", "editorial", "review_ugc", "forum_community"];
  if (highValue.includes(result.publisherType)) score += 20;

  // Freshness
  if (result.freshness === "very_fresh") score += 15;
  else if (result.freshness === "fresh") score += 10;
  else if (result.freshness === "evergreen") score += 5;

  // Assume not in network for now (would need DB lookup)
  score += 15; // Recruitment opportunity bonus

  return Math.min(score, 100);
}

